"use client";

import {
  FloatingFocusManager,
  FloatingList,
  FloatingPortal,
  autoUpdate,
  offset,
  shift,
  size,
  useDismiss,
  useFloating,
  useInteractions,
  useListItem,
  useListNavigation,
  useMergeRefs,
  useRole,
} from "@floating-ui/react";
import { AnimatePresence, motion, useReducedMotion } from "motion/react";
import {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useId,
  useRef,
  useState,
} from "react";
import type * as React from "react";
import { cn } from "@/lib/utils";
import { iconMuted, itemGroupLabel, itemRow, popupDivider, popupSurface } from "@/lib/recipes";
import { Input, type InputProps } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { ChevronDown, Search, X } from "lucide-react";

const MOBILE_MEDIA_QUERY = "(max-width: 767px)";

function useIsMobileCombobox(): boolean {
  const [isMobile, setIsMobile] = useState(false);
  useEffect(() => {
    if (typeof window === "undefined" || !("matchMedia" in window)) return;
    const mql = window.matchMedia(MOBILE_MEDIA_QUERY);
    const update = () => setIsMobile(mql.matches);
    update();
    mql.addEventListener("change", update);
    return () => mql.removeEventListener("change", update);
  }, []);
  return isMobile;
}

/**
 * Combobox - an Input paired with a floating popup that shows arbitrary
 * filterable content (suggestions, recent searches, custom rows). Built on
 * `@floating-ui/react` with virtual focus (input keeps focus, items
 * highlighted via aria-activedescendant) and motion-driven open/close.
 *
 * Unlike `Command`, the popup is anchored to an input and opens on focus.
 * Unlike `Menu`, the trigger is an input: typing filters externally;
 * Combobox doesn't manage filtering, it manages the popup + keyboard
 * navigation + ARIA wiring. You compose the items / content yourself.
 *
 * Usage:
 *   <Combobox value={query} onValueChange={setQuery} placeholder="Search...">
 *     <ComboboxInput prefix={<Search />} />
 *     <ComboboxPopup>
 *       {results.map((r) => (
 *         <ComboboxItem key={r.id} onSelect={() => pick(r)}>
 *           {r.label}
 *         </ComboboxItem>
 *       ))}
 *     </ComboboxPopup>
 *   </Combobox>
 *
 * Below the md breakpoint the popup renders as a bottom-anchored fixed
 * panel with its own search input; desktop is unchanged. For multi-select
 * pickers, pass `closeOnSelect={false}` on ComboboxItem.
 */

type ComboboxContextValue = {
  open: boolean;
  setOpen: (open: boolean) => void;
  activeIndex: number | null;
  setActiveIndex: (i: number | null) => void;
  refs: ReturnType<typeof useFloating>["refs"];
  floatingStyles: React.CSSProperties;
  context: ReturnType<typeof useFloating>["context"];
  getReferenceProps: ReturnType<typeof useInteractions>["getReferenceProps"];
  getFloatingProps: ReturnType<typeof useInteractions>["getFloatingProps"];
  getItemProps: ReturnType<typeof useInteractions>["getItemProps"];
  /** Ref array of item DOM elements. Used by ComboboxInput to activate
   *  the currently highlighted row on Enter, since virtual focus keeps
   *  keyboard focus on the input. */
  elementsRef: React.MutableRefObject<Array<HTMLElement | null>>;
  baseId: string;
  // Query state lives on the root so the trigger input and the mobile panel's
  // own input can share it. Consumers may still override on ComboboxInput.
  value: string | undefined;
  onValueChange: ((next: string) => void) | undefined;
  placeholder: string | undefined;
  isMobile: boolean;
};

const ComboboxContext = createContext<ComboboxContextValue | null>(null);

function useComboboxContext(): ComboboxContextValue {
  const ctx = useContext(ComboboxContext);
  if (!ctx)
    throw new Error("Combobox subcomponents must be used inside <Combobox>");
  return ctx;
}

export interface ComboboxProps {
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  /**
   * Current query string. Wired through context so the trigger input and the
   * mobile panel's own input share it. May still be overridden per-input.
   */
  value?: string;
  /** Called when the query should change. Receives the new string. */
  onValueChange?: (next: string) => void;
  /** Placeholder for the trigger input and the mobile panel input. */
  placeholder?: string;
  /**
   * On open, pre-activate the first item so the row is highlighted and
   * a `ComboboxCheckboxItem`'s checkbox becomes visible without an
   * arrow-down. Default false. Set true for multi-select pickers.
   */
  autoFocusFirst?: boolean;
  children: React.ReactNode;
}

export function Combobox({
  open: controlledOpen,
  defaultOpen = false,
  onOpenChange,
  value,
  onValueChange,
  placeholder,
  autoFocusFirst = false,
  children,
}: ComboboxProps): React.ReactElement {
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const open = controlledOpen ?? uncontrolledOpen;
  const setOpen = useCallback(
    (next: boolean) => {
      if (controlledOpen === undefined) setUncontrolledOpen(next);
      onOpenChange?.(next);
    },
    [controlledOpen, onOpenChange],
  );

  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const elementsRef = useRef<Array<HTMLElement | null>>([]);
  const labelsRef = useRef<Array<string | null>>([]);

  // Ref-mirror of isMobile so the size middleware (which lives outside React)
  // can bail without triggering a `useFloating` re-init on breakpoint change.
  const isMobileRef = useRef(false);

  const { refs, floatingStyles, context } = useFloating({
    open,
    onOpenChange: setOpen,
    placement: "bottom-start",
    transform: false,
    // Combobox semantics: always anchor below the input. `size` constrains
    // maxHeight to whatever fits: popup scrolls internally rather than
    // flipping above the input (Google-search style, not menu-style). On the
    // mobile variant the popup owns its own fixed bottom-anchored geometry,
    // so bail out entirely to avoid clobbering our layout.
    middleware: [
      offset(8),
      shift({ padding: 8 }),
      size({
        apply({ rects, elements, availableHeight }) {
          if (isMobileRef.current) return;
          Object.assign(elements.floating.style, {
            minWidth: `${rects.reference.width}px`,
            maxHeight: `${Math.max(120, Math.min(availableHeight - 8, 400))}px`,
          });
        },
        padding: 8,
      }),
    ],
    whileElementsMounted: autoUpdate,
  });

  const dismiss = useDismiss(context, { outsidePressEvent: "mousedown" });
  const role = useRole(context, { role: "listbox" });
  // Virtual focus: input keeps real focus, items get aria-activedescendant.
  // The proper ARIA combobox pattern.
  const listNavigation = useListNavigation(context, {
    listRef: elementsRef,
    activeIndex,
    onNavigate: setActiveIndex,
    virtual: true,
    loop: true,
  });

  const { getReferenceProps, getFloatingProps, getItemProps } = useInteractions(
    [dismiss, role, listNavigation],
  );

  const baseId = useId();
  const isMobile = useIsMobileCombobox();
  isMobileRef.current = isMobile;

  // On open, optionally pre-activate the first item so a multi-select
  // popup's leading checkbox is visible without an arrow-down. Reset
  // to null on close so re-opens are consistent.
  useEffect(() => {
    if (!open) {
      setActiveIndex(null);
      return;
    }
    if (autoFocusFirst) setActiveIndex(0);
  }, [open, autoFocusFirst]);

  return (
    <ComboboxContext.Provider
      value={{
        open,
        setOpen,
        activeIndex,
        setActiveIndex,
        refs,
        floatingStyles,
        context,
        getReferenceProps,
        getFloatingProps,
        getItemProps,
        elementsRef,
        baseId,
        value,
        onValueChange,
        placeholder,
        isMobile,
      }}
    >
      <FloatingList elementsRef={elementsRef} labelsRef={labelsRef}>
        {children}
      </FloatingList>
    </ComboboxContext.Provider>
  );
}

/* --------------------------- ComboboxInput --------------------------- */

function ChevronIndicator({ open }: { open: boolean }): React.ReactElement {
  return (
    <ChevronDown
      aria-hidden="true"
      className={cn(
        "size-4 shrink-0 text-ink-muted transition-transform duration-[var(--duration-state)] ease-[var(--ease-standard)]",
        open ? "rotate-180" : "rotate-0",
      )}
    />
  );
}

export interface ComboboxInputProps extends InputProps {
  /** Open the popup automatically when the input receives focus. Default true. */
  openOnFocus?: boolean;
  /** Hide the auto-added chevron suffix that indicates open/close state. */
  hideChevron?: boolean;
  /**
   * When true and the input has a non-empty value, renders a trailing × that
   * clears the input. Wire `onClear` to reset your value state.
   */
  clearable?: boolean;
  /** Fired when the user clicks the × to clear. */
  onClear?: () => void;
}

export const ComboboxInput = forwardRef<HTMLInputElement, ComboboxInputProps>(
  function ComboboxInput(
    {
      openOnFocus = true,
      onFocus,
      onKeyDown,
      onClick,
      onChange,
      hideChevron,
      clearable,
      onClear,
      value,
      placeholder,
      suffix: userSuffix,
      ...props
    },
    forwardedRef,
  ) {
    const {
      open,
      setOpen,
      refs,
      getReferenceProps,
      baseId,
      activeIndex,
      elementsRef,
      value: ctxValue,
      onValueChange,
      placeholder: ctxPlaceholder,
    } = useComboboxContext();

    // Prefer the per-input override; fall back to root context. This keeps
    // simple callsites (state on <Combobox>) working while still supporting
    // advanced cases (a controlled override on a single input).
    const effectiveValue = value !== undefined ? value : ctxValue;
    const effectivePlaceholder =
      placeholder !== undefined ? placeholder : ctxPlaceholder;

    const hasValue =
      effectiveValue != null &&
      effectiveValue !== "" &&
      (typeof effectiveValue !== "number" || !Number.isNaN(effectiveValue));
    const showClear = clearable && hasValue && !props.disabled;

    // Build the combobox suffix: user-provided suffix + optional
    // clear × + chevron. The clear × REPLACES the chevron when there
    // is a value to clear; otherwise the chevron indicates open/close
    // state. This keeps the affordance space to a single glyph.
    const suffix = (userSuffix || showClear || !hideChevron) ? (
      <span className="inline-flex items-center gap-1.5">
        {userSuffix}
        {showClear ? (
          <button
            type="button"
            tabIndex={-1}
            aria-label="Clear"
            onClick={(e) => {
              e.stopPropagation();
              onClear?.();
            }}
            className="inline-flex size-5 items-center justify-center rounded-full text-ink-muted hover:bg-surface-2 hover:text-ink transition-colors duration-[var(--duration-state)] ease-[var(--ease-standard)]"
          >
            <X className="size-3" strokeWidth={2.5} />
          </button>
        ) : (
          !hideChevron && <ChevronIndicator open={open} />
        )}
      </span>
    ) : undefined;
    // The Input component wraps the actual <input> in a <span> for icons /
    // suffix / clear button. The visible "field" box is the wrapper span,
    // not the inner input: so anchor floating-ui to the parent element so
    // the popup aligns with the full input chrome (icon included).
    const setReferenceToWrapper = useCallback(
      (node: HTMLInputElement | null) => {
        refs.setReference(node?.parentElement ?? node);
      },
      [refs],
    );
    const inputRef = useMergeRefs([
      forwardedRef,
      setReferenceToWrapper as React.Ref<HTMLInputElement>,
    ]);

    // Pass our handlers THROUGH getReferenceProps so floating-ui can merge
    // them with its own interaction handlers. Spreading getReferenceProps()
    // separately would clobber whichever handlers were declared first.
    const mergedProps = getReferenceProps({
      ...(props as React.HTMLProps<HTMLInputElement>),
      onChange: (e: React.ChangeEvent<HTMLInputElement>) => {
        // Root's onValueChange is the source of truth; any per-input onChange
        // still fires as a side-effect hook (analytics, etc.).
        onValueChange?.(e.target.value);
        onChange?.(e as Parameters<NonNullable<typeof onChange>>[0]);
      },
      onFocus: (e: React.FocusEvent<HTMLInputElement>) => {
        // Base UI's typings re-wrap event types; cast on the user-handler call.
        onFocus?.(e as Parameters<NonNullable<typeof onFocus>>[0]);
        if (openOnFocus && !e.defaultPrevented) setOpen(true);
      },
      onClick: (e: React.MouseEvent<HTMLInputElement>) => {
        onClick?.(e as Parameters<NonNullable<typeof onClick>>[0]);
        if (openOnFocus && !e.defaultPrevented) setOpen(true);
      },
      onKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => {
        onKeyDown?.(e as Parameters<NonNullable<typeof onKeyDown>>[0]);
        if (e.defaultPrevented) return;
        if (!open && (e.key === "ArrowDown" || e.key === "ArrowUp")) {
          e.preventDefault();
          setOpen(true);
          return;
        }
        // Virtual focus keeps the input focused, so items' own onKeyDown
        // never fires. Bridge Enter here by clicking the DOM node of
        // the currently active row.
        if (open && e.key === "Enter" && activeIndex != null) {
          const el = elementsRef.current[activeIndex];
          if (el) {
            e.preventDefault();
            el.click();
          }
        }
      },
    });

    return (
      <Input
        ref={inputRef}
        role="combobox"
        aria-autocomplete="list"
        aria-expanded={open}
        aria-controls={`${baseId}-popup`}
        aria-activedescendant={
          activeIndex != null ? `${baseId}-item-${activeIndex}` : undefined
        }
        autoComplete="off"
        value={effectiveValue}
        placeholder={effectivePlaceholder}
        suffix={suffix}
        {...mergedProps}
      />
    );
  },
);


/* --------------------------- ComboboxPopup --------------------------- */

export interface ComboboxPopupProps {
  className?: string;
  children: React.ReactNode;
}

export function ComboboxPopup({
  className,
  children,
}: ComboboxPopupProps): React.ReactElement | null {
  const {
    open,
    context,
    refs,
    floatingStyles,
    getFloatingProps,
    baseId,
    isMobile,
    setOpen,
    value: ctxValue,
    onValueChange,
    placeholder: ctxPlaceholder,
  } = useComboboxContext();
  const setFloating = useCallback(
    (node: HTMLElement | null) => refs.setFloating(node),
    [refs],
  );
  const reduceMotion = useReducedMotion();

  const popup = (
    <motion.div
      ref={setFloating}
      id={`${baseId}-popup`}
      data-slot="combobox-popup"
      data-variant={isMobile ? "mobile" : "desktop"}
      {...getFloatingProps()}
      style={
        isMobile
          ? undefined
          : {
              ...floatingStyles,
              transformOrigin: "top center",
            }
      }
      initial={reduceMotion ? false : { opacity: 0, scale: 0.97 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={reduceMotion ? undefined : { opacity: 0, scale: 0.97 }}
      transition={
        reduceMotion
          ? { duration: 0 }
          : {
              type: "spring",
              stiffness: 400,
              damping: 30,
              mass: 0.6,
            }
      }
      className={cn(
        // Symmetric surface-1 fill so the popup color matches the
        // Combobox input trigger -- the trigger and its popup read as
        // one continuous surface. shadow-menu carries the elevation
        // lift.
        "flex flex-col overflow-hidden",
        popupSurface,
        isMobile
          ? "pointer-events-auto w-full max-w-md max-h-[calc(100dvh-2rem)]"
          : "z-[80]",
        className,
      )}
    >
      {isMobile && (
        <div
          data-slot="combobox-mobile-header"
          className="flex shrink-0 items-center gap-1 border-b border-hairline pe-2"
        >
          <Input
            variant="unstyled"
            size="lg"
            autoFocus
            autoComplete="off"
            prefix={<Search />}
            value={ctxValue ?? ""}
            onChange={(e) => onValueChange?.(e.target.value)}
            placeholder={ctxPlaceholder}
            aria-label={ctxPlaceholder ?? "Search"}
          />
          <Button
            variant="tertiary"
            size="md"
            shape="circle"
            aria-label="Close"
            onClick={() => setOpen(false)}
            className="text-ink-muted"
          >
            <X className="size-4" />
          </Button>
        </div>
      )}
      <div className="min-h-0 flex-1 overflow-y-auto p-1">{children}</div>
    </motion.div>
  );

  return (
    <FloatingPortal>
      <AnimatePresence>
        {open && (
          // Desktop uses virtual focus (initialFocus={-1}: input keeps real focus,
          // items highlight via aria-activedescendant). Mobile switches to real
          // focus on the panel's own input (initialFocus={0}) since the trigger
          // input is off-screen behind the panel.
          <FloatingFocusManager
            context={context}
            modal={false}
            initialFocus={isMobile ? 0 : -1}
            // Don't programmatically refocus the trigger input on close: the
            // input never lost focus on desktop (virtual focus), and refocusing
            // would fire a focus event that triggers openOnFocus, reopening the
            // popup right after dismiss closed it.
            returnFocus={false}
            visuallyHiddenDismiss
          >
            {isMobile ? (
              // Centered fixed panel with breathing-room margins.
              // Wrapper is pointer-events-none so outside taps still
              // fall through to useDismiss; the popup re-enables them.
              <div className="fixed inset-0 z-[80] flex items-center justify-center p-4 pointer-events-none">
                {popup}
              </div>
            ) : (
              popup
            )}
          </FloatingFocusManager>
        )}
      </AnimatePresence>
    </FloatingPortal>
  );
}

/* --------------------------- ComboboxItem --------------------------- */

export interface ComboboxItemProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSelect"> {
  /** Fired when the user clicks or presses Enter while this item is active. */
  onSelect?: () => void;
  label?: string;
  disabled?: boolean;
  /**
   * Whether to close the popup after selection. Default true (single-select
   * combobox). Set false for multi-select pickers where the user is expected
   * to toggle several items before dismissing.
   */
  closeOnSelect?: boolean;
}

export function ComboboxItem({
  className,
  children,
  onSelect,
  label,
  disabled,
  closeOnSelect = true,
  onClick,
  ...props
}: ComboboxItemProps): React.ReactElement {
  const { activeIndex, getItemProps, setOpen, baseId } = useComboboxContext();
  const itemLabel = label ?? (typeof children === "string" ? children : "");
  const { ref, index } = useListItem({ label: itemLabel });
  const isActive = activeIndex === index;

  const handleSelect = () => {
    if (disabled) return;
    onSelect?.();
    if (closeOnSelect) setOpen(false);
  };

  return (
    <div
      role="option"
      ref={ref}
      id={`${baseId}-item-${index}`}
      aria-selected={isActive}
      aria-disabled={disabled || undefined}
      data-slot="combobox-item"
      data-active={isActive ? "" : undefined}
      data-disabled={disabled ? "" : undefined}
      className={cn(
        // Density matches Menu: comfortable on mobile, compact from md
        // up. Hover mirrors the active fill so pointer + keyboard
        // highlights read the same.
        itemRow.base,
        "cursor-pointer gap-2 transition-colors duration-[var(--duration-state)] ease-[var(--ease-standard)] hover:bg-surface-2",
        iconMuted,
        itemRow.comfortable,
        "md:min-h-7 md:px-2 md:py-1.5 md:text-body-13",
        className,
      )}
      {...getItemProps({
        onClick: (e: React.MouseEvent<HTMLDivElement>) => {
          onClick?.(e);
          if (!e.defaultPrevented) handleSelect();
        },
        onKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => {
          if (e.key === "Enter") {
            e.preventDefault();
            handleSelect();
          }
        },
      })}
      {...props}
    >
      {children}
    </div>
  );
}

/* --------------------------- ComboboxCheckboxItem --------------------------- */

export interface ComboboxCheckboxItemProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSelect" | "prefix"> {
  checked?: boolean;
  onCheckedChange?: (checked: boolean) => void;
  /** Fired when the item is toggled. Called with the new checked state. */
  onSelect?: (checked: boolean) => void;
  label?: string;
  disabled?: boolean;
  /** Leading node (icon) rendered after the checkbox, before the label. */
  prefix?: React.ReactNode;
  /** Trailing node (kbd shortcut, badge, count). */
  suffix?: React.ReactNode;
}

/**
 * Multi-select row inside a Combobox popup. Mirrors MenuCheckboxItem:
 * the leading Checkbox is `opacity-0` on desktop at rest and lifts to
 * `opacity-100` when the row is hovered, keyboard-active, or checked.
 * Always visible on mobile for touch discoverability. The row owns the
 * click; the Checkbox is purely visual.
 */
export function ComboboxCheckboxItem({
  className,
  children,
  checked = false,
  onCheckedChange,
  onSelect,
  label,
  disabled,
  prefix,
  suffix,
  onClick,
  ...props
}: ComboboxCheckboxItemProps): React.ReactElement {
  const { activeIndex, getItemProps, baseId } = useComboboxContext();
  const itemLabel = label ?? (typeof children === "string" ? children : "");
  const { ref, index } = useListItem({ label: itemLabel });
  const isActive = activeIndex === index;

  const toggle = () => {
    if (disabled) return;
    const next = !checked;
    onCheckedChange?.(next);
    onSelect?.(next);
  };

  return (
    <div
      role="option"
      ref={ref}
      id={`${baseId}-item-${index}`}
      aria-selected={isActive}
      aria-checked={checked}
      aria-disabled={disabled || undefined}
      data-slot="combobox-checkbox-item"
      data-state={checked ? "checked" : "unchecked"}
      data-active={isActive ? "" : undefined}
      data-disabled={disabled ? "" : undefined}
      className={cn(
        itemRow.base,
        "group/checkbox-item cursor-pointer gap-2 transition-colors duration-[var(--duration-state)] ease-[var(--ease-standard)] hover:bg-surface-2 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        iconMuted,
        itemRow.comfortable,
        "md:min-h-7 md:px-2 md:py-1.5 md:text-body-13",
        className,
      )}
      {...getItemProps({
        onClick: (e: React.MouseEvent<HTMLDivElement>) => {
          onClick?.(e);
          if (!e.defaultPrevented) toggle();
        },
        onKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => {
          if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            toggle();
          }
        },
      })}
      {...props}
    >
      <Checkbox
        checked={checked}
        tabIndex={-1}
        aria-hidden
        className={cn(
          "pointer-events-none transition-opacity duration-[var(--duration-state)] ease-[var(--ease-standard)]",
          "md:opacity-0",
          "md:group-hover/checkbox-item:opacity-100 md:group-data-[active]/checkbox-item:opacity-100 md:group-data-[state=checked]/checkbox-item:opacity-100",
        )}
      />
      {prefix}
      <span className="min-w-0 flex-1 truncate">{children}</span>
      {suffix && <span className="ms-auto flex items-center">{suffix}</span>}
    </div>
  );
}

/* --------------------------- ComboboxDivider --------------------------- */

/**
 * Edge-to-edge hairline separator inside a Combobox popup. Mirrors
 * MenuDivider: the popup's `p-1` content padding is negated so the line
 * reaches the popup's inner border on both sides.
 */
export function ComboboxDivider({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>): React.ReactElement {
  return (
    <div
      role="separator"
      data-slot="combobox-divider"
      className={cn(popupDivider, className)}
      {...props}
    />
  );
}

/* --------------------------- ComboboxGroupLabel / Section --------------------------- */

/**
 * Section header inside a Combobox popup. Density-aware horizontal
 * padding lines the label's start edge up with item text below --
 * comfortable (mobile) uses px-2.5, compact (desktop from md up) uses
 * px-2 to track the item ramp.
 */
export function ComboboxGroupLabel({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>): React.ReactElement {
  return (
    <div
      data-slot="combobox-group-label"
      className={cn(
        itemGroupLabel.base,
        itemGroupLabel.comfortable,
        "md:px-2",
        className,
      )}
      {...props}
    />
  );
}

/**
 * Compound: a labeled group with consistent vertical rhythm inside a
 * Combobox popup. Sugar for
 * `<div role="group"><ComboboxGroupLabel>{title}</ComboboxGroupLabel>...children...</div>`.
 */
export interface ComboboxSectionProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "children" | "title"> {
  /** Section header text. */
  title?: React.ReactNode;
  children: React.ReactNode;
}

export function ComboboxSection({
  title,
  className,
  children,
  ...props
}: ComboboxSectionProps): React.ReactElement {
  return (
    <div
      role="group"
      data-slot="combobox-section"
      className={cn("py-1 first:pt-0 last:pb-0", className)}
      {...props}
    >
      {title != null && <ComboboxGroupLabel>{title}</ComboboxGroupLabel>}
      {children}
    </div>
  );
}
